#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
  float weight;
  long assign;
  float cost;
} Point_Struct;

#define CACHE_LINE 512

kernel void pgain_kernel(
    global const Point_Struct* p,
    global const float* coord,
    global float* work_mem,
    global const int* center_table,
    global char* switch_membership,
    int num,
    int dim,
    long x,
    int K,
    float z)
{
    int i = get_global_id(0);
    if (i >= num) return;

    float* lower = work_mem + i * (K + 1);

    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[d * num + i] - coord[d * num + x];
        x_cost += diff * diff;
    }
    x_cost *= p[i].weight;

    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        lower[K] += x_cost - current_cost;
    } else {
        int assign = (int)p[i].assign;
        int ct = center_table[assign];
        if (ct >= 0 && ct < K) {
            lower[ct] += current_cost - x_cost;
        }
    }
}

kernel void pgain_center_kernel(
    global const float* work_mem,
    global const int* center_table,
    global const char* is_center,
    global float* gl_lower,
    global int* numclose_ptr,
    global float* cost_adjust_ptr,
    int num,
    int K,
    float z,
    int nproc,
    int stride)
{
    int i = get_global_id(0);
    if (i >= num) return;

    if (is_center[i]) {
        int ct = center_table[i];
        if (ct >= 0 && ct < K) {
            float low = z;
            for (int p = 0; p < nproc; p++) {
                low += work_mem[ct + p * stride];
            }
            gl_lower[ct] = low;

            if (low > 0.0f) {
                *numclose_ptr += 1;
                *cost_adjust_ptr -= low;
            }
        }
    }
}

kernel void pgain_update_kernel(
    global Point_Struct* p,
    global const float* coord,
    global const char* switch_membership,
    global const int* center_table,
    global const float* gl_lower,
    global const char* is_center,
    global int* is_center_out,
    int num,
    int dim,
    long x,
    int gl_cost_negative)
{
    int i = get_global_id(0);
    if (i >= num) return;

    if (gl_cost_negative) {
        int assign = (int)p[i].assign;
        int ct = center_table[assign];
        bool close_center = (ct >= 0 && gl_lower[ct] > 0.0f);

        if (switch_membership[i] || close_center) {
            float x_cost = 0.0f;
            for (int d = 0; d < dim; d++) {
                float diff = coord[d * num + i] - coord[d * num + x];
                x_cost += diff * diff;
            }
            p[i].cost = x_cost * p[i].weight;
            p[i].assign = x;
        }

        if (is_center[i]) {
            int ct = center_table[i];
            if (ct >= 0 && gl_lower[ct] > 0.0f) {
                is_center_out[i] = 0;
            }
        }

        if (i == x) {
            is_center_out[i] = 1;
        }
    }
}
